import os
import subprocess

def convert_image(event, context):
    bucket = event.get("bucket")
    name = event.get("name")
    content_type = event.get("contentType", "")
    metadata = event.get("metadata", {}) or {}

    if not bucket or not name:
        raise ValueError("Missing bucket or object name in event")

    output_format = metadata.get("output_format", "png")
    resize = metadata.get("resize")
    quality = metadata.get("quality")
    extra_args = metadata.get("extra_args", "")

    input_path = os.path.join("/tmp", os.path.basename(name))
    output_filename = os.path.splitext(os.path.basename(name))[0] + "." + output_format
    output_path = os.path.join("/tmp", output_filename)

    cmd = ["convert", input_path]

    if resize:
        cmd.extend(["-resize", str(resize)])

    if quality:
        cmd.extend(["-quality", str(quality)])

    if extra_args:
        if isinstance(extra_args, list):
            cmd.extend([str(arg) for arg in extra_args])
        else:
            cmd.extend(str(extra_args).split())

    cmd.append(output_path)

    download_cmd = ["gsutil", "cp", f"gs://{bucket}/{name}", input_path]
    subprocess.call(download_cmd)

    subprocess.call(cmd)

    return {
        "bucket": bucket,
        "name": name,
        "content_type": content_type,
        "input_path": input_path,
        "output_path": output_path,
        "conversion_command": cmd,
    }